INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_8155501','Я мабуть колись тут був','Музика: Рушничок Слова: Рушничок. Виконує: Рушничок','uk','ukraine_1991',NULL,NULL,NULL,'Цієї пісні часто не буває в інтернетівських альбомах Рушничка. Можливо, це просто недогляд упорядників. А можливо, слова пісні дратують, або сильно засмучують людей, що зреклися (свідомо чи змушені були під пресом обставин) рідної мови та власного імені, про що й співається у пісні.','Я мабуть колись тут був.
Глядів на ції обличчя,
Котрих майже не забув.
Не знав я їх тоді,
І не хотів їх знати,
Бо не було це в моді.

Я пішов в бурхливий світ.
Здобувати собі славу.
Затер по собі слід,
Затаїв свій рід.
В тінях своєї памм''яті
Не дав йому свій плід

Зрікся мови рідної,
Культуру народа занехав,
Бо не вважав її гідної.
Родина моя - та не своя
Діти не знають, хто вони,
Бо я змінив своє ім''я

Так закрив по собі шлях
До рідної сині.
Загибаю в чужих нутрах,
Стою цілком безрадним,
Розірваний болем тим
Болем для мене безпощадним:

Зрікся мови рідної,
Культуру народа занехав,
Бо не вважав її гідної.
Родина моя - та не своя,
Діти не знають, хто вони,
Бо я змінив своє ім''я','[''pisni.org.ua'', ''cat:pisni-pro-movy'', ''Пісні про рідну мову'']',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_8155501'), datetime('now')),datetime('now'));
