INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_8149979','Зустрічаймо Новий рік!','Музика: Володимир Мельников Слова: Володимир Мельников. Виконує: Елеонора Скиданова','uk','ukraine_1991',NULL,'2006','Авторське подання','Ця пісня написана напередодні старого Нового року на музику автора слів і при- свячується усім громадянам україни та народам світу, які вважають Україну рідною землею. Хай вам щастить, дорогі друзі! Російсько-мовний варіант пісні було написано у 2006 році спільно з поетесою Олександрою Присяжнюк з м. Чернігова під назвою "Новый год". Не берите в новый год старых бед, старых бед. Не корите бремя лет, прошлых лет, разных лет. Прошагайте в новый год без хлопот и забот! Пусть вам крупно повезет! Пусть везет, всем везет! Припев: Новый год, Новый год, Новый год! Встретим радостно мы Новый год! Пусть удачу он нам принесет Этот год, добрый год, новый год! Пусть дорога не ведет в Никуда, в Никуда, А Фортуна не уйдет никогда, никогда! Пусть улыбка на лице красит вас, красит вас! Начинайте все дела в добрый час! В добрый час! Припев. Пусть порадуют сейчас и потом, и потом Дети, внуки и друзья, и ваш дом, светлый дом! А за праздничным столом, зажигая свечу, Пожелать вам всем добра и любви я хочу! Припев. Російсько-мовний варіант виконується заслуженою артисткою України Елеонорою Скидановою. Аранжування - Сергія Коваля. Альбом Авторське подання','Зустрічаймо Новий рік без образ
В диво-сяйві ялинкових прикрас.
А усіх, хто вас образив, сьогодні простіть,
І кохання, що пройшло, відпустіть... Відпустіть...

Приспів:
Новий рік! Новий рік!
Зустрічаймо усі Новий рік!
Починаймо щасливо цей рік!
Новий рік! Новий рік! Новий рік!

Зовсім поруч новорічні дива,
І хай обертом іде голова!
Хай дітей, що загубились, нарешті знайдуть,
А нужденним подарують, а не подадуть!

Приспів.

Новий рік нехай підкаже усім
Шлях до скарбу, що відкриє "сім-сім".
Щоб збирались тільки друзі за вашим столом,
Засівайте світ навколо сердечним теплом!

Приспів.','[''pisni.org.ua'', ''cat:new-year'', ''Пісні про Новий Рік'']',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_8149979'), datetime('now')),datetime('now'));
