INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_8156409','Квітка - душа','Музика: Костянтин Меладзе Слова: Діана Гольде. Виконує: Ніна Матвієнко, Антоніна Матвієнко','uk','ukraine_before_1917',NULL,NULL,'акорди: https://mychords.net/nina-matvienko/112320-nina-matvienko-kvitka- dusha.html',NULL,'Ой, не зоря в небі запалала,
То на землі квітка розквітала,
Там де трава, як зелений шовк,
Ранок прийшов, але квітку не знайшов.
Ой то цвіла та не квітка красна,
Ой то душа, що шукала щастя,
Квітка-Душа ніжна і жива,
Вітер почув і приніс її слова.
Приспів:
Весен і зим - дай Бог!
Віри і сил - дай Бог!
Щастя усім - дай Бог!
Ой де Весна коси розплітала,
Квітка цвіла і не облітала,
Мрії і сни, зелена трава,
Тільки душа і квітуча, і жива!
Приспів. (2)
