INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_8151756','Вже більше літ двісті','Українська народна пісня','uk','ukraine_before_1917',NULL,NULL,'Зі слів моїх батьків',NULL,'Вже більше літ двісті як козак в неволі
Понад Дніпром ходить, викликає долю:
"Ой, вийди, вийди із води,
Визволь мене, серденько, із біди".

Не вийду, козаче, не вийду,соколю.
Хоч би м рада вийти, так сама в неволі.
Ой у неволі у ярмі.
Під московським караулом у тюрмі.

Мене нещасливу козацькую долю
Закуто в кайдани, замкнено в неволю.
Ой у неволю, в кайдани,
Нерозумний гетьмане Богдане.

Де ж ти ся поділа, козацькая слава.
Зарита в могили, поросла мурава.
Де ж твої коні вороні?
Чому твої козаченьки у ярмі?

Мої коні в плузі а козак за плугом.
Лиш вітер гуляє, ганяючись Лугом.
Ой ти козаче, покинь плуг.
Сідлай коня вороного тай йди в Луг.','[''pisni.org.ua'', ''cat:kozacki'', ''Козацькі пісні'']',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_8151756'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('pisniua_8151756','Вже більше літ двісті','Вже більше літ двісті як козак в неволі
