INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_8160154','Біда','Українська народна пісня. Виконує: Фольклорний ансамбль села Межирич','uk','ukraine_before_1917',NULL,NULL,'З архіву анс. "Божичі"',NULL,'Ой, біда, подруженьки, біда,
А я зовсім дівчина молода.
Полюбила парубка за селом,
А у нього кучері над чолом.

Довго придивлялася я до них,
Де взя такі кучері чарівні.
А за тії кучері над чолом,
Загубила спокій я за селом.

Цілу ніч простояла я до зорі,
Покусали ніженьки комарі,
А за тії кучері над чолом,
Била мене мати батігом.

Не бий мене, матінко, ой, не бий,
Як Василь повернеться буде мій,
Як Василь повернеться на зорі,
Заспокоє серденько він мені.','[''pisni.org.ua'', ''cat:arkhiv-bozhychi'', ''Фольклорний архів анс. "Божичі"'']',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_8160154'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('pisniua_8160154','Біда','Ой, біда, подруженьки, біда,
А я зовсім дівчина молода.
Полюбила парубка за селом,
А у нього кучері над чолом.

Довго придивлялася я до них,
Де взя такі кучері чарівні.
А за тії кучері над чолом,
Загубила спокій я за селом.

Цілу ніч простояла я до зорі,
Покусали ніженьки комарі,
А за тії кучері над чолом,
Била мене мати батігом.

Не бий мене, матінко, ой, не бий,
Як Василь повернеться буде мій,
Як Василь повернеться на зорі,
Заспокоє серденько він мені.');
