INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_8154154','Маріє гляди','Виконує: Тріо Глорія','uk','ukraine_1991',NULL,NULL,'Страсні пісні',NULL,'Маріє, гляди,
Чиї то сліди?
То сліди твойого Сина,
Тут ішла твоя дитина...
Маріє, не плач...

А вона спішить,
На землю глядить.
Кров багриться слідами,
Як Ісус іде з катами...
Маріє, не плач...

Цілу ніч не спав,
Сину мій любий,
Ти в городі молився
І до смерти готовився,
Дитино моя...

Дитино моя, де ся збираєш?
Де ти годен той хрест нести
І на нім ще днесь повисти?
Дитино моя, моя...

Вже Ісус іде,
Під Хрестом паде,
Рідна матір Го стрічає,
З своїм сином розмовляє:
Де ти, сину, йдеш?

Помогла б Тобі,
Сину мій любий,
Той Хрест тяжкий,
Твоє тіло чим зостати,
Дитино моя...

Вже кричать жиди,
Щоб скоро ішов.
Син на матір подивився,
Гірко слезами облився,
Вже, Маріє, йду...

Мати під Хрестом,
А Син на Хресті,
Серце з жалю умліває,
Як на Сина споглядає,
Маріє, не плач...

Мати вмліває,
А Син вмирає,
Сонце з жаху ся сховало,
Щоб на біль не споглядало,
Маріє, не плач...

Народе грішний,
Що Він вам зробив?
Я одного сина мала
І на смертні муки дала,
За що він терпить?..

Народе грішний,
Що Я вам зробив?
До стовпа мя прив''язали
І терневий вінок дали,
За що ж це таке?..

Народе грішний,
Оцім подумай,
Скоро життя скінчиться
І страшний суд приближиться,
Що ж тоді буде?..    Тріо семінаристів, бр. Андрій Шабанов, бр. Юрій Шабанов, бр. Андрій Хомен - Маріє гляди  (','[''pisni.org.ua'', ''cat:cerkovni'', ''cat:christ'', ''cat:christian'', ''cat:strasni'', ''Церковні пісні'', ''Пісні до Ісуса Христа'', ''Пісні на християнську тематику'', ''Страсні пісні'']',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_8154154'), datetime('now')),datetime('now'));
