INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_8162409','Межи трьома дорогами','Українська народна пісня. Виконує: Остап Кіндрачук','uk','ukraine_before_1917',NULL,NULL,'Остап Кіндрачук','Старовинна весільна пісня з Волині. Наречений тут "князь" (діал. "кнєзь")','Межи трьома дорогами, рано-рано.
Межи трьома дорогами, ранесенько.

Здибалися князь Дажбог, рано-рано.
Здибалися князь Дажбог, ранесенько.

Ой ти боже, ти Дажбоже, рано-рано.
Ой ти боже, ти Дажбоже, ранесенько.

Зверни ж мені з доріженьки, рано-рано.
