INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_8154307','В''язанка лемківська','Українська народна пісня','uk','ukraine_before_1917',NULL,NULL,'Kulik A., Pleśniak P. Dla Oli na słowiańską nutę. Wybrane pieśni łemkowskie, bojkowskie, słowackie, polskie i inne. - Mińsk Mazowiecki, 2001. – 16 p.',NULL,'Ідемо, ідемо,
Дороги не знаємо,
Добрі люди знають,
То нам повідають.

Ідемо, ідемо
І піском, і ледом,
А чи достанемо
Палянички з медом?

Ідемо, ідемо,
Де дві свічки горять,
Будемо стукати,
А чи нам отворят?

Купила мі мама корову
Та й на мою бідну голову.
Казала мі пасти, доїти,
А я рада з хлопцем ходити.

Казала мі січку різати,
Корову гребінцем чесати,
А корова стара, худорлява,
Бодай она здохла до рана.

А я тоту стару корову,
Зажену її кийом до дому,
Поставлю до стайні стояти,
Сама піду з хлопцем гуляти.

Сидит кітка на полиці
В тій червоній рукавици,
Вистромила оченяти
На ті наши молодята.

З далека ж ми приїхали,
Коні нам ся захлистали.
Треба би нам рушничка
Пообтирати коничка.','[''pisni.org.ua'', ''cat:kolomyyky'', ''Коломийки'']',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_8154307'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('pisniua_8154307','В''язанка лемківська','Ідемо, ідемо,
Дороги не знаємо,
Добрі люди знають,
То нам повідають.

Ідемо, ідемо
І піском, і ледом,
А чи достанемо
Палянички з медом?

Ідемо, ідемо,
Де дві свічки горять,
Будемо стукати,
А чи нам отворят?

Купила мі мама корову
Та й на мою бідну голову.
Казала мі пасти, доїти,
А я рада з хлопцем ходити.

Казала мі січку різати,
Корову гребінцем чесати,
А корова стара, худорлява,
Бодай она здохла до рана.

А я тоту стару корову,
Зажену її кийом до дому,
Поставлю до стайні стояти,
Сама піду з хлопцем гуляти.

Сидит кітка на полиці
В тій червоній рукавици,
Вистромила оченяти
На ті наши молодята.

З далека ж ми приїхали,
Коні нам ся захлистали.
Треба би нам рушничка
Пообтирати коничка.');
