INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_8155052','Палала у моєму небі зірка','Музика: Руслан Квінта Слова: Віталій Куровський. Виконує: Наталія Валевська','uk','ukraine_before_1917',NULL,NULL,'аудіозапис','Підбір акордів: Yura13','Dm          C   B♭            F
Вітер на тополі всі гілки зламав,
Він, як я, у долі щастя свого питав.
Dm            C   B♭        F
У ставку - лілеї, у очах - любов,
А десь там над нею зорі падають знов.
Приспів:
B♭   F  G  Am  A
Я й не знала, та й
Палала, палала, палала
У моєму небі зірка!
Падала, падала, падала
Де казали люди "гірко!".
Думала, думала, думала
Збережу своє кохання,
B♭        F
Я кажу: "Ти люби мене
Вперше, як востаннє!"﻿
Ой, вітер, мій вітер, не ламай гілок,
Бо вони ж як діти, скільки ж у них думок!
У ставку лілеї день і ніч цвітуть,
Буду я твоєю, тільки ж ти не забудь!
Приспів.
Палала, палала, палала     |
