INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_815714','Марш Об’єднаної нації','(Ми разом, багато, і нас не подолати!). Музика: Sergio Ortega Слова: Sergio Ortega, Володимир Некрасов','uk','ukraine_1991',NULL,NULL,'http://www.cym.org/ua','Помаранчева пісня про помаранчеві події, написана у середовищі Спілки Української Молоді в Україні; детальніша інформація на сайті cym.org/ua. Це - сумівський мистецький внесок. За ініціативою друга Володимира Некрасова (Київський осередок) та активної участі друга Ігоря Косика (Львівський осередок) записано революційний марш на відому мелодію, українські слова якого мають актуальне в наш час звучання. Запис здійснено на студії ФДР Радіоцентру. Жіночі голоси в записі - також сумівські... (http://www.cym.org/ua/) Назва пісні-оригіналу (іспанською мовою) - "Marcha de la unidad popular". Назва україномовної версії - "Марш Об’єднаної нації" (або "Ми разом, багато, і нас не подолати!"). Слова (іспанською мовою) та музика – Sergio Ortega. Ідея та слова українською мовою - Володимир Некрасов. * Один із використаних тут акордів: H7sus4 [2 5 2 4 2 2] ** У першому відомому аудіо-варіанті 3-го україномовного куплету не було. Замість нього - програш. Натомість приспів укінці звучав двічі. Тут відразу після першого приспіву був такий текст: La patria esta forjando la unidad. De norte a sur se movilizara, desde el salar ardiente y mineral al bosque austral, unidos en la lucha y el trabajo iran la patria cubriran. Su paso ya anuncia el porvenir. Останній варіант аудіозапису (mp3) пісні шукайте на http://www.cym.org/ua/ Доповнення до тексту і коментарів надав Ігор Косик. Підбір акордів: Володимир Некрасов','(без музики, соло вокаліста)
El pueblo unido jamas sera vencido! (2)

(далі - під музику)
(хором)
El pueblo unido jamas sera vencido! (2)

(соло вокаліста)
De pie, marchar que vamos a triunfar.
Avanzan ya banderas de unidad,
y tu vendras marchando junto a mi
y asi veras tu canto y tu bandera
al florecer la luz de un rojo amanecer
anuncia ya la vida que vendra.

(хором)
Лунає грім з карпатських полонин
І голос сурми ллється над степами
Дзвенить Софії золотавий дзвін
Наш прапор помаранчевий. За волю
Станем брате мій з тобою як один
Зігрієм єдністю наші серця.

Заспів:
Am(V)          F#7
Від Сяну до Дону ми України діти!
G                   H7sus4     H7  *
Ми станем за правду! Свободу не спинити!

Приспів:
Ми разом, багато, і нас не подолати!  (2)

Ми не скорились фальші та брехні
Не залякали нас лихі погрози
Тримаєм міцно прапор бойовий
Що помаранчем зігріва морозний день
До перемоги станем як один
Навіки разом у одній сім''ї.

Бо ми нащадки славних козаків  **
Плекаєм дух стрілецької звитяги
Повстанську пісню на сто голосів
Ми заспіваєм і складем присягу
Що за Україну станем як один
Здобудем волю рідної землі.

Заспів.
Приспів.  (2)','[''pisni.org.ua'', ''cat:himny-marshi'', ''cat:suspilno-politychni'', ''Гимни та марші'', ''Суспільно-політичні пісні'']',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_815714'), datetime('now')),datetime('now'));
