INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_815116','Реве та стогне Дніпр широкий','Музика: Данило Крижанівський Слова: Тарас Шевченко. Виконує: Народний хор Стежина, REMIX, Іван Козловський, Іван Паторжинський, Хор імені Григорія Верьовки, Назарій Яремчук, Вадим Швидкий','uk','ukraine_before_1917',NULL,NULL,NULL,NULL,'Реве та стогне Дніпр широ_кий,
