INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_8160171','Доярка','Українська народна пісня. Виконує: Фольклорний ансамбль села Межирич','uk','ukraine_before_1917',NULL,NULL,'З архіву ансамблю "Божичі"',NULL,'У колгоспі я робила,
Корови доїла,
Умивалась молоком,
Щоб я була біла.

Умивалась молоком
Під дубом зеленим,
Полюбила бригадира
З кучерявим чубом.

Полюбила бригадира
Другої бригади,
А ще треба полюбить
Голову сільради.

Голова сільради
Низенького росту,
Треба мені полюбить
Голову колгоспу.

Прийшла до контори,
Сіла я на лавку:
Товарищу голова,
Дайте мені справку.

Дайте мені справку,
Щоб я була певна,
На роботу не ходила
Й получала прем''я.

А ти, жінко молода,
Іди собі до дому,
Справку дам я тобі,
Не кажи нікому.

Товарищу голова,
Приходь на вечерю,
Я бутилку куплю
Ще й качку печену.

Не приходить голова
На другу бригаду,
Бо розбита голова
З переду і з заду.

Оце тобі, голова,
За чужі учинки,
Щоб ти справку не давав
Для чужої жінки!','[''pisni.org.ua'', ''cat:arkhiv-bozhychi'', ''cat:socialno-pobutovi'', ''Фольклорний архів анс. "Божичі"'', ''Соціально-побутові пісні'']',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_8160171'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('pisniua_8160171','Доярка','У колгоспі я робила,
Корови доїла,
Умивалась молоком,
Щоб я була біла.

Умивалась молоком
Під дубом зеленим,
Полюбила бригадира
З кучерявим чубом.

Полюбила бригадира
Другої бригади,
А ще треба полюбить
Голову сільради.

Голова сільради
Низенького росту,
Треба мені полюбить
Голову колгоспу.

Прийшла до контори,
Сіла я на лавку:
Товарищу голова,
Дайте мені справку.

Дайте мені справку,
Щоб я була певна,
На роботу не ходила
Й получала прем''я.

А ти, жінко молода,
Іди собі до дому,
Справку дам я тобі,
Не кажи нікому.

Товарищу голова,
Приходь на вечерю,
Я бутилку куплю
Ще й качку печену.

Не приходить голова
На другу бригаду,
Бо розбита голова
З переду і з заду.

Оце тобі, голова,
За чужі учинки,
Щоб ти справку не давав
Для чужої жінки!');
