INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_8159116','Косив батько, косив я','Українська народна пісня. Виконує: Фольклорний ансамбль села Межирич','uk','ukraine_before_1917',NULL,NULL,'Фольклорний архів ансамблю "Божичі". Запис в с.Межирич (Маврино) Павлоградського р-ну Дніпропетровської обл. 12.08.1993 Касета 3',NULL,'Та косив батько, косив я,
Та викосили солов''я.
Соловей у саду, соловеєчко.

Приспів:
Роман косе, Гапка в''яже,
Катерина загріба,
Грицько воли напува,
Ганна воду налива.

Ой, мамо, люблю Гриця,
Гриць на конику вертиться,
В Гриця шапка до лиця,
Люблю Гриця-молодця!

Приспів.

Та прийди, Грицю, у неділю,
Дам тобі сорочку білу.
Соловей в саду, соловеєчко.

Приспів.

Дам сорочку-вишиванку
Та й простоїмо до ранку.

Приспів','[''pisni.org.ua'', ''cat:arkhiv-bozhychi'', ''Фольклорний архів анс. "Божичі"'']',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_8159116'), datetime('now')),datetime('now'));
