INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_816603','Горіла Сосна Смерека','Українська народна пісня','uk','ukraine_before_1917',NULL,NULL,'с. 415-416, два заспіви. № 847 Весільні пісні. У двох книгах. Книга 2 (Волинь, Поділля, Буковина, Прикарпаття, Закарпаття). Упор., примітки Шубравської М.М., нотний матеріал упор. Бучель Н.А. - Українська народна творчість. Т. 17 (у двох книгах). Київ, Наукова Думка, 1982. 679с.','* Кожна стрічка співається двічі Пара — любощі: Весілля. Сосна-Вогонь-Вінок. Еротика, жарти, забави: Катерини – Калета – Андрія... Гаїлки-Великдень... Зелені Свята... Івана Купала... Весілля... – Щедровечірнє й Новорічне: Маланки-Василь. Коза. Кіт... – Мед і Ябка... Десь узялася Молода Дівчина. Стала ж Вона сяяти. Горіла Сосна палала. Стежки до листків про Українські традиції.','Горіла Сосна Смерека
Сподобав ми ся здалека

Горіла Сосна ще й Явір
Сподобав ми ся Кавалір

Горіла Сосна палала
Під нев Дівчина стояла

Під нев Дівчина стояла
Русяву Косу чесала

Ой Коси-коси ви мої
Довго служили ви мені

Більше служить не будете
Під Білий Вельон підете

Під Білий Вельон під Хустку
Більш не будете за Дружку

Під Білий Вельон з Кінцями
Більш не підете з Хлопцями

Під Білий Вельон під Вінок
Більше не підете у Танок

Горіла Сосна у той день
Музика грала цілий день','[''pisni.org.ua'', ''cat:dances'', ''cat:philosophic'', ''cat:vesilni'', ''cat:waltzes'', ''Пісні до танцю'', ''Філософські пісні'', ''Весільні пісні'', ''Вальси'']',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_816603'), datetime('now')),datetime('now'));
