INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_8167817','Зірочки яснії','Слова: Платон Воронько','uk','ukraine_before_1917',NULL,NULL,'http://www.malecha.org.ua/',NULL,'У широкому вікні
Є три зірочки ясні:
Перша - зірочка щаслива,
Друга - зірочка вродлива,
Третя - зірочка правдива,
Вірні подруги вони.

Люба донечко, засни
І тоді до тебе в сні
Всі три зірочки ясні
Прийдуть у таночку
В золотім віночку.

Щоб росла щаслива,
Щоб росла правдива
Донечка вродлива...','[''pisni.org.ua'', ''cat:kolyskovi'', ''Колискові'']',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_8167817'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('pisniua_8167817','Зірочки яснії','У широкому вікні
Є три зірочки ясні:
Перша - зірочка щаслива,
Друга - зірочка вродлива,
Третя - зірочка правдива,
Вірні подруги вони.

Люба донечко, засни
І тоді до тебе в сні
Всі три зірочки ясні
Прийдуть у таночку
В золотім віночку.

Щоб росла щаслива,
Щоб росла правдива
Донечка вродлива...');
