INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_8167807','В лісі є зелена хата','Музика: Юрий Крылатов Слова: Платон Воронько','uk','ukraine_before_1917',NULL,NULL,'http://www.malecha.org.ua/',NULL,'В лісі є зелена хата,
Там поснули ведмежата,
А найменший - вереда,
Сивій мамі набрида.

Каже: Я не хочу спати,
Утечу вночі із хати,
Коли меду не даси,
Риби, сала, ковбаси!

Люлі-люлі, треба спати, -
Над синком шепоче мати:
Як заснеш, тобі усе
Сон в кошівці принесе','[''pisni.org.ua'', ''cat:dytyachi'', ''cat:kolyskovi'', ''Дитячі пісні'', ''Колискові'']',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_8167807'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('pisniua_8167807','В лісі є зелена хата','В лісі є зелена хата,
