INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_8166154','Сини','Музика: Олександр Пляченко Слова: Вадим Крищенко. Виконує: Віктор Шпортько','uk','ukraine_1991',NULL,NULL,'Книга: Крищенко В. Д. Усі ми прагнемо любові: Пісні.-Київ:ВіРА ІНСАЙТ-2003',NULL,'А вже сини спинаються на крила,
А вже сини рушають у політ,
Бо мрія давня небеса відкрила,
Бо дивиться надія їм услід.

Приспів:
Сини, сини - хай вас біда обходить,
Сини, сини - вам серце передам.
Хай наше поле українське родить
І хай же доля усміхнеться вам.

Коли серця і щирі, і натхненні -
Добро на світі правдою стає...
Ой, щось у вас від батька та від нені,
А щось у вас усе-таки своє.

Приспів.

Життя летить, як на вихрястих конях,
Із мужністю єднаються сини...
Чого ж так рано на синівських скронях
З''являється тривога сивини?

Приспів.','[''pisni.org.ua'', ''cat:pro-ditey'', ''Пісні про любов до дітей'']',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_8166154'), datetime('now')),datetime('now'));
