INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_8171103','На гору Оливну','Слова: о. Й. Кишакевич','uk','ukraine_1991',NULL,NULL,'Господь - моя пісня: Збірник релігійних пісень. - Львів: Свідчадо, 2005. - 656 с.',NULL,'На гору Оливну з сумом
Йдуть Апостоли святі,
А з очей їх ллються струмом
Гіркі сльози дрібнії:
"Серце наше з болю в''яне,
Не лишай же, Спасе, нас,
Хто ж у помочі нам стане    |
У важкий, пекучий час?      | (2)

Ми з Тобою так, як діти,
Йшли, куди Ти нас повів:
Хто ж без Тебе дрібні цвіти
Охоронить від гріхів?"
Спас промовив у спокою,
Тиха мова поплила:
"Як ви довго є зі Мною,     |
Так Я з вами довіка".       | (2)

"Не полишу сиротами,
Вас любимих, на землі,
А пішлю Святого Духа
Вам у поміч з небеси.
Доки ви, любі, зі Мною,
Доти з вами Дух Святий,
3 Ним побіда ваша в бою     |
На весь світ і всіх людей!" | (2)','[''pisni.org.ua'', ''cat:cerkovni'', ''Церковні пісні'']',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_8171103'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('pisniua_8171103','На гору Оливну','На гору Оливну з сумом
Йдуть Апостоли святі,
А з очей їх ллються струмом
Гіркі сльози дрібнії:
"Серце наше з болю в''яне,
Не лишай же, Спасе, нас,
Хто ж у помочі нам стане    |
У важкий, пекучий час?      | (2)

Ми з Тобою так, як діти,
Йшли, куди Ти нас повів:
Хто ж без Тебе дрібні цвіти
Охоронить від гріхів?"
Спас промовив у спокою,
Тиха мова поплила:
"Як ви довго є зі Мною,     |
Так Я з вами довіка".       | (2)

"Не полишу сиротами,
Вас любимих, на землі,
А пішлю Святого Духа
Вам у поміч з небеси.
Доки ви, любі, зі Мною,
Доти з вами Дух Святий,
3 Ним побіда ваша в бою     |
На весь світ і всіх людей!" | (2)');
