INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_816777','Пам’яти тридцяти','Музика: Марія Бурмака Слова: Павло Тичина. Виконує: Марія Бурмака','uk','ukrainian_peoples_republic_1917_1921',NULL,NULL,'Аудіо-альбом: Марія Бурмака. Марія. 1992; http://www.burmaka.kiev.ua/al_maria.htm','Присвячено Подвигу Героїв Крут: "Вони - студенти, курсанти, школярі... без вагань віддали молоде життя в ім''я волі свого народу... Це - символ нескореного духу нашої нації. Це - пересторога тим, хто і нині сподівається поставити націю на коліна..." Детальніше >>','На Аскольдовій могилі
Поховали їх —
Тридцять мучнів українців,
Славних, молодих...
G
На Аскольдовій могилі
Український цвіт! —
По кривавій   по дорозі
Нам іти у світ.
На кого посміла знятись
Зрадницька рука? —  *
Квітне сонце, грає вітер
І Дніпро-ріка...
На кого зазнявся воїн?  **
Боже, покарай! —
Понад все вони любили
Свій коханий край.
Вмерли в Новім Заповіті
З славою святих. —
На Аскольдовій могилі
Поховали їх.
На Аскольдовій могилі  ***
Український цвіт! —
По кривавій по дорозі
Нам іти у світ.','[''pisni.org.ua'', ''cat:bardivski'', ''cat:istorychni'', ''cat:kruty'', ''Бардівські пісні'', ''Історичні пісні'', "Пісні пам''яті Героїв бою під Крутами"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_816777'), datetime('now')),datetime('now'));
