INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_8170654','Стрітення','Музика: А. Гнатишин Слова: о. В. Б. Мендрунь','uk','ukraine_1991',NULL,NULL,'Господь - моя пісня: Збірник релігійних пісень. - Львів: Свідчадо, 2005. - 656 с.',NULL,'Мати Діва йде сьогодні,
Тужний старець їх стрічає,
Йде з хлоп''ям у храм Господній,
Щасні руки простягає.

Приспів:
Радістю сповнися, мій народе,
Вже спасіння над тобою сходить,
Бог живий між нами!

Від гріха Він оборона.
Віра славить Симеона:
Відпусти мене, Владико,
Вістку всім звіщу велику.

Приспів.

Згине царство лиходія!
На руках святих — Месія.
Це Марії жертва люба,
Це для пекла — меч і згуба.

Приспів.','[''pisni.org.ua'', ''cat:cerkovni'', ''Церковні пісні'']',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_8170654'), datetime('now')),datetime('now'));
