INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_8168705','В суботойку та й за сонця','Українська народна пісня','uk','ukr_ssr_1919_1991',NULL,'1965','Пісні з Волині, "Музична Україна", Київ - 1970','Весільні пісні. Записана в с. Колодяжне Ковельського р-ну від Х.В.Ківшик, 1965','В суботойку та й за сонця
Сіла дівчина в оконця,
Всі думойки передумала,
Дружечок та здумала:
"Ви, мої дружечки, ви мої,
Звийте віночок ви мені,
Бо я завтра часу не матиму,
