INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_8172013','З повной щирой груди','Музика: о.В.Стех Слова: о.В.Стех','uk','ukraine_1991',NULL,NULL,'Господь - моя пісня. Збірник релігійних пісень. Упор. Т.Ференц, І.Мельник, О.Костецька. Львів, "Свічадо", 2005.',NULL,'З повной щирой груди пісню заспіваймо
Улашківську Матір Божу прославляймо.    (2)

Тут Вона вславилась в храмі чудесами,
Тут істочник ласки знайдуть християни.  (2)

А проте до Неї ми завжди горнімся
І в потребах наших всі до Неї молімся.  (2)

Привітайте Діву, ангела словами:
Радуйся Маріє, радуйся між нами!     (2)

О леліє чиста! Від снігу біліша,
Кращая над сонце, над зірки ясніша.  (2)

Будь благословенна і возвеличена,
В небі і на землі всіми ублаженна.   (2)

Дай Тебе любити, вірно Ти служити,
А по смерти в царстві враз з Тобою жити.  (2)    комп''ютерне відтворення','[''pisni.org.ua'', ''cat:do-bohorodyci'', ''Пісні до Богородиці'']',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_8172013'), datetime('now')),datetime('now'));
