INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_8172307','Станьмо згідно','Музика: о. М. Федорів Слова: о. А.Трух','uk','ukraine_1991',NULL,NULL,'Господь - моя пісня: Збірник релігійних пісень. - Львів: Свідчадо, 2005. - 656 с.',NULL,'Станьмо згідно, друг при друзі,
Грімко пісню задзвенім,
І в Марійськім нашім крузі
Честь Марії голосім.
Бо Марія - наша мати        |
І заступниця свята,         |
Їй належну честь віддати -  |
Це найближча всіх мета!     | (2)

Непорочна, чиста, красна,
Повна ласки й всіх чеснот,
Мов та зірка світла, ясна,
Сяє все з святих висот.
І царює з Сином в небі,     |
Людям ласки шле в потребі,  |
І хоронить всіх від зла.    | (2)

Хто Марію щиро любить,
Вірно йде Її слідом,
Той мети життя не згубить:
Вічно житиме з Христом!
То ж до Неї друзі милі,     |
Поспішаймо радо все,        |
Рано-вечір, в кожній хвилі, |
Нас Марія всіх прийме.      | (2)

Станьмо згідно, друзі милі,
Стяг лелійний піднесім
І Марії — всі в цій хвилі
Вічну вірність присягнім.
Бо Марія всіх приймає       |
Під небесний омофор,        |
Хто з любови підіймає       |
Пресвятий Її прапор.        | (2)','[''pisni.org.ua'', ''cat:do-bohorodyci'', ''Пісні до Богородиці'']',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_8172307'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('pisniua_8172307','Станьмо згідно','Станьмо згідно, друг при друзі,
Грімко пісню задзвенім,
І в Марійськім нашім крузі
Честь Марії голосім.
