INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_8175154','Будеш ти, мамичко','Українська народна пісня','uk','ukraine_before_1917',NULL,NULL,'Антологія лемківської пісні, Львів, "Афіша", 2005, с.121','Виконує: Осип Ференц, с.Висова Альбом:','1. Будеш ти, мамичко, горенько плакати,
Як ти буде єдна лижка зоставати.

2. Зостане ти лижка, і в полю робота,
Будеш ти плакала, як бідни сирота.

3. Далас мене, мамо, за третю границю,
Жеби м не ходила до тя по жентицю.

4. Ани по жентицю, ани по молоко,
Далас мене, мамо, од себе далеко.

5. Вибивай, мамичко, зо стіни клиночок,
Де Ганця вішала зелений віночок','[''pisni.org.ua'', ''cat:lemkivski'', ''cat:vesilni'', ''Лемківські пісні'', ''Весільні пісні'']',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_8175154'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('pisniua_8175154','Будеш ти, мамичко','1. Будеш ти, мамичко, горенько плакати,
Як ти буде єдна лижка зоставати.

2. Зостане ти лижка, і в полю робота,
Будеш ти плакала, як бідни сирота.

3. Далас мене, мамо, за третю границю,
Жеби м не ходила до тя по жентицю.

4. Ани по жентицю, ани по молоко,
Далас мене, мамо, од себе далеко.

5. Вибивай, мамичко, зо стіни клиночок,
Де Ганця вішала зелений віночок');
