INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_8175474','Ох, у неділю рано-пораненьку','(Пісня про Коваленка). Українська народна пісня','uk','ukraine_before_1917',NULL,NULL,'Книга:Українські народні пісні;В 2 книгах;Київ,"Мистецтво"1955;Кн1,стр.25-26',NULL,'Ох, у неділю рано-пораненьку,
Ох, і зібрав женців а той Коваленко.
Да й усе женці да й одбірнії,
Поробив їм серпи да все золотії.
Ой повів женців на ярі долини,
На ярі долини, на яру пшеницю.
"Ой жніте, женчики, обжинайтеся,
І на чорную хмару озирайтеся,
А я піду додому пообідаю,
Жінку та діточок да одвідаю".
Ох, і жнуть женці, розжинаються,
На чорную хмару озираються.
Ой то ж не хмара, то орда іде,
А Коваленко та передок веде.
В''язали руки да сирицею,
А залили очі да живицею.
А залили очі да живицею,
А скували ніжки да скрипицею.
"Ой повій, вітроньку, да з-під ночі,
Да розкуй мої да руки-ніженьки,
Ох, повій, вітроньку, з-під темної ночі
Да на мої ж на карії очі!"','[''pisni.org.ua'', ''cat:istorychni'', ''Історичні пісні'']',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_8175474'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('pisniua_8175474','Ох, у неділю рано-пораненьку','Ох, у неділю рано-пораненьку,
Ох, і зібрав женців а той Коваленко.
Да й усе женці да й одбірнії,
Поробив їм серпи да все золотії.
Ой повів женців на ярі долини,
На ярі долини, на яру пшеницю.
"Ой жніте, женчики, обжинайтеся,
І на чорную хмару озирайтеся,
А я піду додому пообідаю,
Жінку та діточок да одвідаю".
Ох, і жнуть женці, розжинаються,
На чорную хмару озираються.
Ой то ж не хмара, то орда іде,
А Коваленко та передок веде.
В''язали руки да сирицею,
А залили очі да живицею.
А залили очі да живицею,
А скували ніжки да скрипицею.
"Ой повій, вітроньку, да з-під ночі,
Да розкуй мої да руки-ніженьки,
Ох, повій, вітроньку, з-під темної ночі
Да на мої ж на карії очі!"');
