INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_8173518','Моє дитинство золоте','Музика: Наталія Май Слова: Наталія Май. Виконує: Наталія Май','uk','ukraine_1991',NULL,NULL,'аудіозапис',NULL,'Від отчого порога у білий світ дорога
Терновим цвітом забринить.
Та, щоб життя пізнати, неначе пташеня,
Ми вилітаємо в блакить!
І пам''ятаєм свято матусині поради:
Слова і мудрі, і прості.
У щасті і недолі не забувай ніколи
Ту землю, де вродився ти!

Приспів:
Моє дитинство золоте
У снах журавкою курличе,
Воно мене до дому кличе,
Де мальва за вікном цвіте!
Моє дитинство золоте
Мене у спогадах колише
І руки мами найніжніші,
Я Богу дякую за те!

А десь далеко зорі і небо неозоре,
Веселка птахою зліта!
Та наймиліша в світі одна стежина в житті,
Яка до дому поверта.
Зігріє і розрадить матусина порада:
Слова і мудрі, і прості.
У щасті і недолі не забувай ніколи
Ту землю, де вродився ти!

Приспів. (2)','[''pisni.org.ua'', ''cat:pro-batkiv'', ''Пісні про любов до батьків'']',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_8173518'), datetime('now')),datetime('now'));
