INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_817205','Надія є','Музика: Вадим Красноокий Слова: Вадим Красноокий. Виконує: Mad Heads (XL)','uk','ukraine_1991',NULL,NULL,NULL,NULL,'Intro: C G Am F

Коли опустилися руки
Коли потемніло в очах
Не знаєш ти, як далі бути
На що сподіватись хоча б.

Не можеш, не віриш, не знаєш
Не маєш куди утікти
І кажуть - чудес не буває
Та мусиш для себе знайти.

Приспів:
Допоки сонце сяє, поки вода тече
Надія є.
Лиха біда минає, просто повір у це
Надія є.

Тобі вже нічого не треба
Бо ти вже нічого не встиг
Здається, що всі проти тебе
А, може, то ти проти них.

Не можеш позбутися болю
Не знаєш, чи прийде весна
Ти можеш не вірити долі,
Але в тебе вірить вона!

Приспів.','[''pisni.org.ua'', ''cat:patriotic'', ''Патріотичні пісні'']',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_817205'), datetime('now')),datetime('now'));
