INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_8176676','Маршерують добровольці','Українська народна пісня. Виконує: Хор Бурлака','uk','ukraine_before_1917',NULL,NULL,NULL,NULL,'Машерують добровольці
Як колись ішли стрільці
Сяють їм шоломи в сонці,
Грає усміх на лиці.

Приспів:
Хто живий, хто живий,
В ряд ставай, в ряд ставай,
Визволяти,
Здобувати рідний край!

Перед ними молодими
Розігнався в полі шлях.
А над ними небo синє,
Ясний усіх на устах.

Приспів.

Вже не буде ворог лютий
Розпинать на хрест батьків
І не влиє в серце вже отрути -
В чисті серця юнаків.

Приспів.','[''pisni.org.ua'', ''cat:istorychni'', ''Історичні пісні'']',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_8176676'), datetime('now')),datetime('now'));
