INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_81756','Тільки раз цвіте любов','Музика: Володимир Івасюк Слова: Богдан Стельмах. Виконує: Олександр Пономарьов, Софія Ротару, Василь Зінкевич, Олег Марцинківський','uk','ukraine_before_1917',NULL,NULL,'http://ivasyuk.domivka.net/',NULL,'Поглянь, усе навколо зацвіло,
Ясна вода і сонце золоте.
Цвітуть гаї, цвіте усе зело,
Чому ж любов так довго не цвіте?
Так довго?
Приспів:
Cm pause                  Cm       A#
В ріку перероста дзвінкий ручай,
Журбою розцвіта гірка печаль.
А ранок сонцем кожен день цвіте для нас,
G# pause               Cm            Gm Cm Gm...
І лиш любов цвіте один-єдиний раз.
Стрімка ріка загубиться в морях,
Журбу розвіють радощі весни.
Минеться все, але любов моя
Не зронить цвіту навіть восени.
Не зронить...
Приспів. (2)','[''pisni.org.ua'', ''cat:krasa-pryrody'', ''cat:lirychni'', ''Пісні про красу природи'', ''Пісні про кохання, ліричні'']',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_81756'), datetime('now')),datetime('now'));
