INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_8177714','Мово рідна моя, не мовчи!','Музика: Надія Красоткіна Слова: Надія Красоткіна. Виконує: Надія Красоткіна','uk','ukraine_1991',NULL,NULL,'http://krasotkina.com',NULL,'Мово, веселим струмочком біжи
Та об''єднай всі джерельця малі.
Про Україну усім розкажи —
Дивний, чарівний куточок землі.

Мово, струмочки в ріку об''єднай,
Дужим потоком течи серед квіт.
І на Землі зазвучи, заспівай,
Щоб прислухався до тебе весь світ!

Я із калини сопілку зроблю,
Щоб розбудити ранкову зорю.
Мову свою я всім серцем люблю,
Нею співаю і говорю.

Мовою рідною славлю я день,
Працю і хліб, що лежить на столі.
Скільки звучить українських пісень
В різних куточках святої землі!

Мово прекрасна моя, не мовчи,
Не загубись поміж іншими ти,
А соловейком весною звучи.
Сміло, крилато у світі лети!

Сил набирайся і гордо злітай,
Благословляю тебе на політ!
Мово чарівна, звучи і співай,
Щоб прислухався до тебе весь світ!','[''pisni.org.ua'', ''cat:pisni-pro-movy'', ''Пісні про рідну мову'']',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_8177714'), datetime('now')),datetime('now'));
