INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_81777','Сизокрилий птах','Музика: Джером Баккі, Володимир Івасюк Слова: Роман Кудлик. Виконує: Софія Ротару','uk','ukraine_1991',NULL,NULL,NULL,NULL,'О сизокрилий птах, ти моє серце
Із синіх верховин поніс у далину,
Лишив мене сумну зустрінути весну.

О сизокрилий птах,
Згубився шлях твій у житах,
Даремно вітер перейма - тебе вже нема.

Серце, наче птах,
Полинуло б у світ на ста семи вітрах.
Та рветься із грудей лише палкої пісні туга,
Як ронять вишні білий цвіт
За вітром вслід (в світ?).

О, прилети,
Мою весну, ти, мій коханий, захисти,
Щоб їй розцвісти.

Серце, наче птах,
Полинуло б у світ на ста семи вітрах.
Та рветься із грудей
Лише палкої пісні туга,
Як ронять вишні білий цвіт
Із ранніх літ','[''pisni.org.ua'', ''cat:nostalgia'', ''Пісні з ностальгічними мотивами'']',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_81777'), datetime('now')),datetime('now'));
