INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_817358','117-а стаття','Музика: Брати Гадюкіни Слова: Брати Гадюкіни. Виконує: Брати Гадюкіни','uk','ukraine_before_1917',NULL,NULL,NULL,NULL,'тюрма тюрма
дай мені кличку
стаття 117
путьовий

їде столипін
колеса стучат
ніч надворі
всі бродяги вже сплят
я один не сплю
думу думаю
про тяжку долю свою
і 117 статтю

Приспів:
117 стаття
117 стаття
117 стаття
доля молодьожная

я поклеїв малолєтку
її я полюбив
ну не так шоб полюбив
але півтижня з нев ходив
потім чу-чуть їй дав під хвіст
потім сказав їй бай-бай
вона була зовсім тупа
любила миколайчука

Приспів.

чувіха все повіла мамі
а та підняла шум і гам
гворе плати тисячу баксів
або під суд тебе віддам
а їй сказав
шо за ті гроші
я можу виграти її
її сестру і братову
і всю родину на селі

Приспів.

Акорди, спрощено (bohdanko):

Програш: E D A E

A
Їде Столипін, колеса стучат.
Ніч надворі. Всі бродяги вже сплят.
Я один не сплю, думу думаю
про тяжку долю свою   і 117-ту статтю.

Приспів
117-та стаття, 117-та стаття,
117-та стаття - доля молодьожная.','[''pisni.org.ua'', ''cat:zhartivlyvi'', ''Жартівливі пісні'']',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_817358'), datetime('now')),datetime('now'));
