INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_8173807','Медова нічка','(Нічка чарівниця). Музика: Володимир Домшинський Слова: Вадим Крищенко. Виконує: Квартет "Гетьман"','uk','ukraine_1991',NULL,NULL,NULL,NULL,'Духмяна нічка з настоєм хвої,
А попід небом та й стояли двоє,
Медова нічка крилом накрила,
А хто з них милий, а хто з них мила?

Приспів:
Нічка, нічка, нічка, нічка чарівниця,
Скільки ти з''єднала одиноких доль
І мені не спиться, і комусь не спиться,
Тож побуть з тобою, ніченько, дозволь!
Нічка, нічка, нічка, нічка чарівниця,
Ти життя загадку знаєш не одну,
Хто твою відкриє ніжну таємницю,  |
Хто твою пізнає вічну таєну?      | (2)

Чорнява нічка, пітьма зірчаста
Даруєш смуток і даруєш щастя
Бездонна нічка, високі світки
Як вип''єм вина - не бачать вічки.

Приспів. (2)','[''pisni.org.ua'', ''cat:krasa-pryrody'', ''Пісні про красу природи'']',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_8173807'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('pisniua_8173807','Медова нічка','Духмяна нічка з настоєм хвої,
А попід небом та й стояли двоє,
Медова нічка крилом накрила,
