INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_8175450','Била мене мати паличком з ліщини','Українська народна пісня','uk','ukraine_before_1917',NULL,NULL,'Антологія лемківської пісні, Львів, "Афіша", 2005, с.218','Виконує: Іван Пиж, с.Вапенне','1. Била мене мати паличком з ліщини,
Жеби я не ходив до вадной дівчини. (2)

2. А я си змудрував, паличку м попсував,
До дівчати м ходив, аж єм підскакував. (2)

3. Дівчатко-дівчатко, зроблю я ти цяцько,
З ручками, з ножками, з сивими очками. (2)

4. Янічку-златовлас, цілуй моє личко,
А цяцько нам зробиш, як буду женичком. (2)','[''pisni.org.ua'', ''cat:lemkivski'', ''Лемківські пісні'']',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_8175450'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('pisniua_8175450','Била мене мати паличком з ліщини','1. Била мене мати паличком з ліщини,
Жеби я не ходив до вадной дівчини. (2)

2. А я си змудрував, паличку м попсував,
До дівчати м ходив, аж єм підскакував. (2)

3. Дівчатко-дівчатко, зроблю я ти цяцько,
З ручками, з ножками, з сивими очками. (2)

4. Янічку-златовлас, цілуй моє личко,
А цяцько нам зробиш, як буду женичком. (2)');
