INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_8178307','Святий Миколаю','Музика: Анжела Вербицька Слова: Анжела Вербицька. Виконує: Анжела Вербицька','uk','ukraine_1991',NULL,NULL,'аудіозапис',NULL,'Миколаю!

У Святого Миколая
Попрошу диво чудес,
Знає Він і помагає,
Бачить все із-під небес,
Миколаю дорогенький,
Зроби так, щоб діточки
Тебе слухали з маленька,
Виросли, як квіточки.

Приспів:
Чудотворче Миколаю,
Море милості й чудес,
У любові вихваляєм,
Посланий Ти із небес!
З Мир Лікійських Миколая
Величає цілий світ,
Наша пісня хай лунає
І на многа-многа літ!

Хто слухняний був і чемний,
Братам меншим помагав,
Той торбиночку таємну
Вже з-під подушки дістав.
А прийде така година,
Коли Ти спитаєш нас:
Чи усі в своїх родинах
Шанували Твій образ.

Приспів.

Миколаю!

І запрошуєм гостинно:
Завітай до нас сюди!
Ми зібралися родинно,
Тож, благаємо, прийди!
Наділи нас благодаттю,
Миром, розумом, добром,
У натхненні і завзятті
Переможемо ми зло!

Приспів.

Миколаю!','[''pisni.org.ua'', ''cat:svyatyy-mykolay'', ''Пісні про Святого Миколая'']',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_8178307'), datetime('now')),datetime('now'));
