INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_8176950','Пісня про матір','Музика: Василь Їжак Слова: Степан Пушик. Виконує: Михайло Сливоцький','uk','ukraine_1991',NULL,NULL,'Книга: Пісенник, Київ, "Спалах", 2000, с.219-220.',NULL,'Земля дочекалась і рясту, і сонця, і цвіту,
Душа, мов калина, росте і цвіте без тепла.
Нічого не треба, нічого не хочу від світу,
Лишень аби мати на білому світі була.

З-за гір віє вітер, в степах повмирали морози,
Шумлять осокори, весняно зітхають гаї,
А мати старенька стоїть на високім порозі,
Та й думає мати, як маються діти її.

А діти світами, а діти у веснах та в зимах,
Приїдуть і скажуть: "Нам двері, матусю, втворіть".
І доти всі діти живуть по світах молодими,
Допоки чекають, допоки живі матері.

Земля молодіє від рясту, від сонця, від цвіту,
Душа, мов калина, росте і цвіте від тепла.
Нічого не треба, нічого не хочу від світу,
Лишень аби мати на білому світі була','[''pisni.org.ua'', ''cat:pro-batkiv'', ''Пісні про любов до батьків'']',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_8176950'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('pisniua_8176950','Пісня про матір','Земля дочекалась і рясту, і сонця, і цвіту,
