INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_817817','Балада про принцесу','Музика: Руслана Слова: Анна Кривута. Виконує: Руслана','uk','ukraine_1991',NULL,'1998',NULL,'Руслана, 1998 Мить весни.','Дальня путь лежить
Через хмари і небес блакить,
Там в чужім краю
Не знайде вона любов свою,
Бо вбиває золото красу.

Вона була подібна до сонця -
Принцеса луків.
Вона одна володарка лісу -
Тварин і птахів.
Зростаючи в некошених травах -
Серед лілей.
Вона була променем світла -
Серед людей.

Тільки не знайшла все,
До чого прагнула душа.
Золото й парча залишили
Обпік на плечах
І отруту смерті на устах.

Вона була неначе дитина -
Принцеса луків.
Вона одна володарка лісу -
Тварин і птахів.
Зростаючи в некошених травах -
Серед лілей.
Вона була дитиною світла -
І світлом людей.

Але ніхто не в силах
Згасити сонце в безодні зла,
Ніхто не в силах спинити розталь,
Вір, я жива...

Па-па-па...
Побачиш там до небокраю -
Зелень луків.
Побачиш сам володарку лісу -
Тварин і птахів.
Я там живу де сонце розквітло -
Серед лілей.
Назвеш мене принцесою світла
І світлом людей.

Знову я прийду до тебе,
Я з''явлюсь у світлу мить,
Тільки треба справді вірити...
Я тобі в частинку неба
Назбираю всю блакить,
Тільки треба справді вірити...
А коли зберуться хмари над землею,
Не забудь, через сонячні луки
В казку путь...','[''pisni.org.ua'', ''cat:krasa-pryrody'', ''Пісні про красу природи'']',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_817817'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('pisniua_817817','Балада про принцесу','Дальня путь лежить
Через хмари і небес блакить,
Там в чужім краю
Не знайде вона любов свою,
Бо вбиває золото красу.

Вона була подібна до сонця -
Принцеса луків.
Вона одна володарка лісу -
Тварин і птахів.
Зростаючи в некошених травах -
Серед лілей.
Вона була променем світла -
Серед людей.

Тільки не знайшла все,
До чого прагнула душа.
Золото й парча залишили
Обпік на плечах
І отруту смерті на устах.

Вона була неначе дитина -
Принцеса луків.
Вона одна володарка лісу -
Тварин і птахів.
Зростаючи в некошених травах -
Серед лілей.
Вона була дитиною світла -
І світлом людей.

Але ніхто не в силах
Згасити сонце в безодні зла,
Ніхто не в силах спинити розталь,
Вір, я жива...

Па-па-па...
Побачиш там до небокраю -
Зелень луків.
Побачиш сам володарку лісу -
Тварин і птахів.
Я там живу де сонце розквітло -
Серед лілей.
Назвеш мене принцесою світла
І світлом людей.

Знову я прийду до тебе,
Я з''явлюсь у світлу мить,
Тільки треба справді вірити...
Я тобі в частинку неба
Назбираю всю блакить,
Тільки треба справді вірити...
А коли зберуться хмари над землею,
Не забудь, через сонячні луки
В казку путь...');
