INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_818409','Пливе качур','(Пливе качур в гороховім вінку). Українська народна пісня','uk','ukraine_before_1917',NULL,NULL,NULL,NULL,'Пливе качур (2), в гороховім вінку (2),
Вибирай си, качурику, щонайкращу дівку (2),
І та гарна, і та гарна, і та непогана (2),
А тамтая дівчинонька, як намальована (2),
Не казала стара мати, дівчат вибирати (2),
А казала стара мати, сиротоньку взяти (2),
Бо бідная сиротонька, буде працювати (2),
А багата розкішниця, схоче йно лежати (2),
Рубай сину ясенину, будуть добрі клини (2),
Бери сину сиротину, буде господиня (2),
Не з кожної ясенини, будуть добрі клини (2),
Не з кожної сиротини, буде господиня (2),
"Ой чи ж тебе, дівчинонько, маляр вимальовав (2),
Що на твоє біле личко, фарби не жаловав?" (2)
"Мене маляр не мальовав, а сам Господь з неба (2),
Я, молода дівчинонька, мені краси треба" (2).','[''pisni.org.ua'', ''cat:vesnyanky-hayivky'', ''Веснянки та гаївки'']',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_818409'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('pisniua_818409','Пливе качур','Пливе качур (2), в гороховім вінку (2),
Вибирай си, качурику, щонайкращу дівку (2),
І та гарна, і та гарна, і та непогана (2),
